            raise ValueError('Invalid amount range')

        return {
            'response': {
                'actionGroup': 'extraction',
                'apiPath': '/validate',
                'httpStatusCode': 200,
                'completion': json.dumps(extracted_data)
            }
        }
    except Exception as e:
        return {
            'response': {
                'actionGroup': 'extraction',
                'apiPath': '/validate',
                'httpStatusCode': 400,
