import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

const invoiceSchema = {
  type: 'object',
  properties: {
    invoiceNumber: { type: 'string', pattern: '^[A-Z0-9-]{8,}$' },
    date: { type: 'string', format: 'date' },
    amount: { type: 'number', minimum: 0, maximum: 1000000 },
    vendor: { type: 'string', minLength: 2 }
  },
  required: ['invoiceNumber', 'amount']
};

async function verifiedAgentCall(document: string) {
  const agentResponse = await invokeExtractionAgent(document);

  const verified = await vex.verify(agentResponse, {
    schema: invoiceSchema,
    assertions: [
      (data: any) => data.amount > 0 || 'Amount must be positive',
      'All required fields present'
    ]
  });

  return verified;
}
